class Patient:

    def __init__(self, id, name, age, gender, diagnosis, treatment_plan):
        self.id = id
        self.name = name
        self.age = age
        self.gender = gender
        self.diagnosis = diagnosis
        self.treatment_plan = treatment_plan
patients = {bytes.fromhex('50303031').decode(): Patient(bytes.fromhex('50303031').decode(), bytes.fromhex('4a6f686e20446f65').decode(), 45, bytes.fromhex('4d616c65').decode(), bytes.fromhex('487970657274656e73696f6e').decode(), bytes.fromhex('4d656469636174696f6e20616e64206c6966657374796c65206368616e676573').decode())}

def create_person_report(patient_code, report_template):
    bytes.fromhex('').decode()
    if patient_code not in patients:
        raise ValueError(bytes.fromhex('50617469656e74206e6f7420666f756e64').decode())
    patient = patients[patient_code]
    report = report_template.replace(bytes.fromhex('7b70617469656e742e69647d').decode(), patient.id)
    report = report.replace(bytes.fromhex('7b70617469656e742e6e616d657d').decode(), patient.name)
    report = report.replace(bytes.fromhex('7b70617469656e742e6167657d').decode(), str(patient.age))
    report = report.replace(bytes.fromhex('7b70617469656e742e67656e6465727d').decode(), patient.gender)
    return report